questionvariables.text:
/* 1. Define side lengths of a triangle */
/* We'll use a 3-4-5 right triangle for clean numbers */
base: 3 * (1 + rand(2));   /* 3 or 6 */
height: 4 * (base/3);      /* 4 or 8 */
hypotenuse: 5 * (base/3);  /* 5 or 10 */

/* 2. Calculate Original Perimeter */
ta1: base + height + hypotenuse;

/* 3. Define a Negative Scale Factor */
/* Note: We use a non-integer to make it challenging */
sf: -0.5 - (2.5 * rand(3)); /* -0.5, -1.0, or -1.5 */

/* 4. Teacher Answer: Perimeter of Image */
/* Perimeter scales by the absolute value of k */
ta2: ta1 * abs(sf);
